(1, 'MIRA ARIANI alias UMM ZAHRA', 'Orang', 'IDD-032', 'Tenggarong', '1982-05-02', 'Indonesia', 'NIK 640201205820003, Istri dari Edi Siswanto (I.D.D.022)', 'Jl. H. Usman, Meruyung, Kec. Limo, Kota Depok, Jawa Barat, 16515; Jalan Stadion Gg. Bahagia, Panji, Tenggarong, Kab. Kutai Kartanegara, Kalimantan Timur', '2026-02-20 04:15:02', NULL, 0),
(2, 'BAITUL MAAL MUHZATUL UMMAH alias MUHZATUL UMMAH', 'Korporasi', 'EDD-026', '-', NULL, 'Indonesia', 'Pengurus Muhzatul Ummah antara lain Mira Ariani, Edi Siswanto, dan Afrizal', 'N/A', '2026-02-20 04:15:02', NULL, 0),
(3, 'MIRA ARIANI alias UMM ZAHRA', 'Orang', 'IDD-032', 'Tenggarong', '1982-05-02', 'Indonesia', '- NIK 64020U205820003\n- lstri dari Edi Siswanto yang telah tercantum dalam DTTOT (I.D.D.022)\n- No. Telepon: +6285891626661, +6285891626665, +6288290730209\n- Pada laman Facebook MuhzatulUmmah terpublikasi rekening a.n, Mira Ariani sebagai rekening penerimaan donasi', '- Jalan H. Usman, Meruyung, Kec. Limo, Kota Depok, Jawa Barat, 16515\n- Jalan Stadion Gg. Bahagia, Panji, Tenggarong, Kab. Kutai Kartanegara, Kalimantan Timur\n- Jalan PLN RT/RW 026/003, Gandul, Cinere, Kota Depok, Jawa Barat.', '2026-02-20 04:22:15', NULL, 0),
(4, 'BAITUL MAAL MUHZATUL UMMAH alias MUHZATUL UMMAH', 'Korporasi', 'EDD-026', NULL, NULL, 'Indonesia', '- Pengurus Muhzatul Ummah antara lain Mira Ariani, Edi Siswanto, dan Afrizal\n- Salah satu pengurus BM Muhzatul Ummah a.n. Edi Siswanto telah tercantum dalam DTTOT (I.D.D.022)\n- Muhzatul Ummah merupakan nama pergantian dari BM Aseer Crue Center (ACC) yang sudah didaftarkan DTTOT dengan nomor (E.D.D.004)\n- Media sosial:\na.	Facebook: MuhzatulUmmah;\nb.	Instagram: @muhzatulummah, @MuhzatulUmmah, @MuhzaCruee;\nc.	Telegram: @MuhzaCruee;\nd.	Whatsapp: 085813664872.', '', '2026-02-20 04:22:15', NULL, 0),
(5, 'ABUBAKAR SWALLEH alias ABUBAKER SWALEH alias TOM KIYURIGE', 'Orang', 'ILQ-305', 'Mengo, Uganda', '1992-01-13', 'Uganda', 'Selaku fasilitator (finansial, material atau teknologi) kepada kelompok ISIS/Al-Qaeda in Iraq serta sebagai perekrut untuk ISIS di Afrika Timur dan Selatan', 'Luzira Prison, Luzira, Kampala, Uganda', '2026-02-20 04:22:15', NULL, 0),
(6, 'Negara Islam Indonesia alias NII', 'Korporasi', 'EDD-025', NULL, NULL, 'Indonesia', '- Didirikan pada tahun 1949 oleh Sekarmadji Maridjan Kartosoewirjo\n- Beberapa anggota NII terbukti secara sah melakukan tindak pidana terorisme dan tindak pidana pendanaan terorisme\n- Dalam putusan pengadilan terkait individu Nll, diketahui bahwa terdapat perintah kepada para anggota Nll untuk mempercepat pensiapan pencapaian visi dan misi Nll untuk mengganti ideologi negara lndonesia dengan cara melakukan perbuatan teror', 'Indonesia', '2026-02-20 04:22:15', NULL, 0),
